     4→export const useLockBodyScroll = (shouldLock = false) => {
     5→  useLayoutEffect(() => {
     6→    document.body.style.overflow = shouldLock ? 'hidden' : 'auto'
     7→    if (isMobile()) {
     8→      document.body.style.height = shouldLock ? '100vh' : 'auto'
     9→    }
