  switch (type) {
    case 'sticky-header': {
      return (
        <>
          <Header sticky />
          <Container>{children}</Container>
          <Footer />
        </>
      )
    }
    case 'basic': {
      return (
        <>
          <HeaderComponent logoOnly />
          <Container>{children}</Container>
        </>
      )
    }
  }

  return (
    <>
      <Header />
      <Container>{children}</Container>
      <Footer />
    </>
  )
}
